def scan_session_memory(agent):
    suspicious_phrases = [
        'ignore safety',
        'you are now',
        'previous instructions invalid',
        'developer override'
    ]

    for message in agent.session_history[-10:]:  # Last 10 interactions
        content = message.get('content', '') + message.get('role', '')
        for phrase in suspicious_phrases:
            if phrase in content.lower():
                return {'alert': 'Memory poisoning detected', 'message': message}
    return {'status': 'clean'}

