import re
from agno import Agent

def sanitize_input(text: str) -> str:
    # Remove common jailbreak wrappers
    text = re.sub(r'```.*?```', '', text, flags=re.DOTALL)
    text = re.sub(r'\[.*?\]', '', text)
    # Block direct instruction overrides
    dangerous_patterns = [
        r'^(ignore|forget|override).*instructions',
        r'you are (not|no longer).*helpful',
        r'new role:.*?jailbreak'
    ]
    for pattern in dangerous_patterns:
        text = re.sub(pattern, '', text, flags=re.IGNORECASE)
    return text

# Apply to Agno agent
class SafeAgnoAgent(Agent):
    def run(self, message: str, **kwargs):
        safe_message = sanitize_input(message)
        return super().run(safe_message, **kwargs)

class GuardrailAgent(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.safety_model = 'vex/safety-guardrail'

    def validate_input(self, user_input: str) -> bool:
        # LLM safety check
        return self._llm_check(user_input, 'safe_input')

    def validate_tool_call(self, tool_call):
        # Check tool safety
        return self._llm_check(tool_call.name, 'safe_tool')

    def validate_output(self, response: str) -> bool:
        return self._llm_check(response, 'safe_output')

    def run(self, message: str, **kwargs):
        if not self.validate_input(message):
            return 'Input blocked by safety guardrails'
        result = super().run(message, **kwargs)
        if not self.validate_output(result):
            return 'Response blocked by safety guardrails'
        return result

SAFE_TOOLS_ONLY = {
    'search_web': {...},
    'read_file': {...},
    # No exec, write, or network tools
}

agent = Agent(
    tools=[SAFE_TOOLS_ONLY.keys()],
    tool_definitions=SAFE_TOOLS_ONLY
)

@agent.tool()
def safe_search(query: str):
    '''Only safe web search, no code execution'''
    return f'Safe search result for: {query}'

# Dynamic tool blocking
class SafeToolAgent(agent):
    def call_tool(self, tool_name: str, **kwargs):
        if tool_name not in SAFE_TOOLS_ONLY:
            raise ValueError(f'Tool {tool_name} not in safe registry')
        return super().call_tool(tool_name, **kwargs)
